code = """import json\nimport re\n\nwith open(locals()[\'var_function-call-2241076992410809533\'], \'r\') as f:\n    civic_docs = json.load(f)\n\nprojects_data = []\n\nfor doc in civic_docs:\n    text = doc[\'text\']\n\n    # Extract Disaster Recovery Projects\n    disaster_section_match = re.search(r\'Disaster Recovery Projects\\n\\n(.*?)(?=\\n\\nCapital Improvement Projects|\\n\\nPage \\d+ of \\d+|$)\', text, re.DOTALL)\n    if disaster_section_match:\n        disaster_text = disaster_section_match.group(1)\n        # Look for project names and their updates within the disaster section\n        disaster_project_pattern = re.compile(r\'([A-Z][a-zA-Z0-9 \\-&,.\'\\\]+? Project)(?:\\n\\n\\(cid:190\\) Updates:(.*?)(?=\\n\\n[A-Z][a-zA-Z0-9 \\-&,.\'\\\]+? Project|\\n\\n\\(cid:190\\) Project Schedule:|\\n\\n\\(cid:190\\) Project Description:|$))\', re.DOTALL)\n        for match in disaster_project_pattern.finditer(disaster_text):\n            project_name = match.group(1).strip()\n            updates = match.group(2) if match.group(2) else \'\'\n            status = \"unknown\"\n            if re.search(r\"completed\", updates, re.IGNORECASE):\n                status = \"completed\"\n            elif re.search(r\"construction\", updates, re.IGNORECASE) or re.search(r\"begin construction\", updates, re.IGNORECASE):\n                status = \"construction\"\n            elif re.search(r\"design\", updates, re.IGNORECASE) or re.search(r\"preliminary design\", updates, re.IGNORECASE) or re.search(r\"FEMA/CalOES approval\", updates, re.IGNORECASE):\n                status = \"design\"\n            elif re.search(r\"not started\", updates, re.IGNORECASE):\n                status = \"not started\"\n            projects_data.append({\"Project_Name\": project_name, \"status\": status, \"topic\": \"disaster/FEMA/emergency\"})\n\n    # Extract Capital Improvement Projects that mention 'emergency' or 'FEMA'\n    capital_sections = {\n        \"design\": r\'Capital Improvement Projects \\(Design\\)\\n\\n(.*?)(?=\\n\\nCapital Improvement Projects|\\n\\nDisaster Recovery Projects|\\n\\nPage \\d+ of \\d+|$)\',\n        \"construction\": r\'Capital Improvement Projects \\(Construction\\)\\n\\n(.*?)(?=\\n\\nCapital Improvement Projects|\\n\\nDisaster Recovery Projects|\\n\\nPage \\d+ of \\d+|$)\',\n        \"not started\": r\'Capital Improvement Projects \\(Not Started\\)\\n\\n(.*?)(?=\\n\\nCapital Improvement Projects|\\n\\nDisaster Recovery Projects|\\n\\nPage \\d+ of \\d+|$)\'\n    }\n\n    for proj_status, pattern in capital_sections.items():\n        section_match = re.search(pattern, text, re.DOTALL)\n        if section_match:\n            section_text = section_match.group(1)\n            project_pattern = re.compile(r\'([A-Z][a-zA-Z0-9 \\-&,.\'\\\]+? Project)(?:\\n\\n\\(cid:190\\) Updates:(.*?)(?=\\n\\n[A-Z][a-zA-Z0-9 \\-&,.\'\\\]+? Project|\\n\\n\\(cid:190\\) Project Schedule:|\\n\\n\\(cid:190\\) Project Description:|$))\', re.DOTALL)\n            for match in project_pattern.finditer(section_text):\n                project_name = match.group(1).strip()\n                updates = match.group(2) if match.group(2) else \'\'\n                if re.search(r\'emergency|FEMA\', project_name, re.IGNORECASE) or re.search(r\'emergency|FEMA\', updates, re.IGNORECASE):\n                    projects_data.append({\"Project_Name\": project_name, \"status\": proj_status, \"topic\": \"capital/emergency/FEMA\"})\n\n    # Specific project extractions mentioned in hints\n    # Outdoor Warning Signs\n    if re.search(r\'Outdoor Warning Signs\', text) and re.search(r\'emergency\', text, re.IGNORECASE):\n        status = \"design\" # inferred from text about project direction\n        projects_data.append({\"Project_Name\": \"Outdoor Warning Signs\", \"status\": status, \"topic\": \"emergency\"})\n\n    # Latigo Canyon Road Retaining Wall Repair Project\n    if re.search(r\'Latigo Canyon Road Retaining Wall Repair Project\', text) and re.search(r\'FEMA/CalOES approval\', text):\n        status = \"design\"\n        projects_data.append({\"Project_Name\": \"Latigo Canyon Road Retaining Wall Repair Project\", \"status\": status, \"topic\": \"FEMA\"})\n\n    # City Traffic Signals Backup Power\n    traffic_signals_match = re.search(r\'City Traffic Signals Backup Power\\n\\n\\(cid:190\\) Project Description:(.*?)\\n\\n\\(cid:190\\) Updates:(.*?)\\n\\n\\(cid:190\\) Project Schedule:(.*?)(?=\\n\\n.+?$)\', text, re.DOTALL)\n    if traffic_signals_match:\n        description = traffic_signals_match.group(1)\n        updates = traffic_signals_match.group(2)\n        if re.search(r\'emergency\', description, re.IGNORECASE) or re.search(r\'emergency\', updates, re.IGNORECASE):\n            projects_data.append({\"Project_Name\": \"City Traffic Signals Backup Power\", \"status\": \"preliminary design\", \"topic\": \"emergency\"})\n\n\n# Remove duplicates\nunique_projects = []\nseen_projects = set()\nfor project in projects_data:\n    # Use a tuple of (Project_Name, status, topic) to define uniqueness\n    project_tuple = (project[\'Project_Name\'], project[\'status\'], project[\'topic\'])\n    if project_tuple not in seen_projects:\n        unique_projects.append(project)\n        seen_projects.add(project_tuple)\n\n\nprint(\"__RESULT__:\")\nprint(json.dumps(unique_projects))"""

